using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- DI setup ----------------------------------------------------------------

var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddSingleton(new Notebook());

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var provider = services.BuildServiceProvider();

var chatClient = provider.GetRequiredService<IChatClient>();
var notebook = provider.GetRequiredService<Notebook>();
var logger = provider.GetRequiredService<ILogger<Program>>();

// --- Tools -------------------------------------------------------------------

var tools = new AIFunctionFactory();

var searchTool = tools.Create(
    ([Description("The search query to look up on the web")] string query) =>
    {
        return SearchWebAsync(query);
    },
    new AIFunctionFactoryOptions
    {
        Name = "search_web",
        Description = "Searches the web for the given query and returns a list of result snippets. "
                    + "Use this to find information about a topic.",
    });

var addNoteTool = tools.Create(
    ([Description("A concise note capturing a key finding")] string note) =>
    {
        notebook.Add(note);
        return $"Note saved. You now have {notebook.Notes.Count} note(s).";
    },
    new AIFunctionFactoryOptions
    {
        Name = "add_note",
        Description = "Saves a research note. Use this to record important findings as you research. "
                    + "Each note should capture one key fact or insight.",
    });

var readNotesTool = tools.Create(
    () =>
    {
        if (notebook.Notes.Count == 0)
            return "No notes taken yet.";

        return string.Join("\n", notebook.Notes.Select((n, i) => $"{i + 1}. {n}"));
    },
    new AIFunctionFactoryOptions
    {
        Name = "read_notes",
        Description = "Returns all research notes taken so far. "
                    + "Use this to review your findings before writing a summary.",
    });

// --- Agent setup -------------------------------------------------------------

var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research assistant. Your job is to research a topic thoroughly
        and produce a well-organized summary.

        Follow this process:
        1. Search the web for the topic using multiple varied queries to get broad coverage.
        2. After each search, save the most important findings as notes using add_note.
        3. Once you have gathered enough information (at least 3-5 searches), read your
           notes with read_notes, then produce a final summary.

        Your final response should be a clear, well-structured summary with key points.
        Always cite what you found in your searches.
        """,
    Tools = [searchTool, addNoteTool, readNotesTool],
};

// --- Main loop ---------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        🔍 AI Research Agent              ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.Write("> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notebook.Clear();
    Console.WriteLine($"\nResearching: {topic}\n");

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
    };

    var options = new AgentInvokeOptions
    {
        MaximumIterations = 10,
        ModelOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
        },
    };

    try
    {
        await foreach (var message in agent.InvokeStreamingAsync(history, options))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
            {
                Console.Write(message.Text);
            }

            logger.LogDebug("Agent step: Role={Role}, ContentLength={Length}",
                message.Role, message.Text?.Length ?? 0);
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError during research: {ex.Message}");
    }

    Console.WriteLine("\n");
}

Console.WriteLine("Goodbye!");

// --- Web search implementation -----------------------------------------------

static async Task<string> SearchWebAsync(string query)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    try
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "ResearchAgent/1.0 (Console; .NET 10)");

        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        var html = await http.GetStringAsync(url);

        var results = ParseDuckDuckGoResults(html);

        if (results.Count == 0)
            return "No results found for this query.";

        return string.Join("\n\n", results.Select((r, i) =>
            $"[{i + 1}] {r.Title}\n{r.Snippet}"));
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

static List<SearchResult> ParseDuckDuckGoResults(string html)
{
    var results = new List<SearchResult>();
    var resultBlocks = html.Split("class=\"result__body\"", StringSplitOptions.RemoveEmptyEntries);

    foreach (var block in resultBlocks.Skip(1).Take(5))
    {
        var title = ExtractBetween(block, "class=\"result__a\"", "</a>");
        var snippet = ExtractBetween(block, "class=\"result__snippet\"", "</a>");

        if (title is not null)
        {
            title = StripHtmlTags(title);
            snippet = snippet is not null ? StripHtmlTags(snippet) : "";
            results.Add(new SearchResult(title.Trim(), snippet.Trim()));
        }
    }

    return results;
}

static string? ExtractBetween(string text, string startMarker, string endMarker)
{
    var startIdx = text.IndexOf(startMarker, StringComparison.Ordinal);
    if (startIdx < 0) return null;
    startIdx = text.IndexOf('>', startIdx + startMarker.Length);
    if (startIdx < 0) return null;
    startIdx++;
    var endIdx = text.IndexOf(endMarker, startIdx, StringComparison.Ordinal);
    if (endIdx < 0) return null;
    return text[startIdx..endIdx];
}

static string StripHtmlTags(string html)
{
    var result = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "");
    return System.Net.WebUtility.HtmlDecode(result).Trim();
}

// --- Supporting types --------------------------------------------------------

record SearchResult(string Title, string Snippet);

class Notebook
{
    public List<string> Notes { get; } = [];
    public void Add(string note) => Notes.Add(note);
    public void Clear() => Notes.Clear();
}

