    Console.WriteLine($"\nResearching: {topic}\n");

    var history = new List<ChatMessage>
    {
        new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
    };

    var options = new AgentInvokeOptions
    {
        MaximumIterations = 10,
        ModelOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
        },
    };

    try
    {
        await foreach (var message in agent.InvokeStreamingAsync(history, options))
        {
            if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
            {
                Console.Write(message.Text);
            }

            logger.LogDebug("Agent step: Role={Role}, ContentLength={Length}",
                message.Role, message.Text?.Length ?? 0);
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"\nError during research: {ex.Message}");
    }

    Console.WriteLine("\n");
}

Console.WriteLine("Goodbye!");

// --- Web search implementation -----------------------------------------------

static async Task<string> SearchWebAsync(string query)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    try
    {
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd(
            "ResearchAgent/1.0 (Console; .NET 10)");

        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";
        var html = await http.GetStringAsync(url);

        var results = ParseDuckDuckGoResults(html);

        if (results.Count == 0)
            return "No results found for this query.";

        return string.Join("\n\n", results.Select((r, i) =>
            $"[{i + 1}] {r.Title}\n{r.Snippet}"));
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Try a different query.";
    }
}

static List<SearchResult> ParseDuckDuckGoResults(string html)
{
    var results = new List<SearchResult>();
    var resultBlocks = html.Split("class=\"result__body\"", StringSplitOptions.RemoveEmptyEntries);

    foreach (var block in resultBlocks.Skip(1).Take(5))
    {
        var title = ExtractBetween(block, "class=\"result__a\"", "</a>");
        var snippet = ExtractBetween(block, "class=\"result__snippet\"", "</a>");

        if (title is not null)
        {
            title = StripHtmlTags(title);
            snippet = snippet is not null ? StripHtmlTags(snippet) : "";
            results.Add(new SearchResult(title.Trim(), snippet.Trim()));
        }
    }

    return results;
}

static string? ExtractBetween(string text, string startMarker, string endMarker)
{
    var startIdx = text.IndexOf(startMarker, StringComparison.Ordinal);
    if (startIdx < 0) return null;
    startIdx = text.IndexOf('>', startIdx + startMarker.Length);
    if (startIdx < 0) return null;
    startIdx++;
    var endIdx = text.IndexOf(endMarker, startIdx, StringComparison.Ordinal);
    if (endIdx < 0) return null;
    return text[startIdx..endIdx];
}

static string StripHtmlTags(string html)
{
    var result = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "");
    return System.Net.WebUtility.HtmlDecode(result).Trim();
}

// --- Supporting types --------------------------------------------------------

record SearchResult(string Title, string Snippet);

class Notebook
{
    public List<string> Notes { get; } = [];
    public void Add(string note) => Notes.Add(note);
    public void Clear() => Notes.Clear();
}

